MAP
#
#< Start of map file - created 2011-05-12 - 10:52:16
#
NAME 'CATBR_TEMATICO'
STATUS ON

PROJECTION
			'init=epsg:32720'     # UTM 20, Zona 20S, WGS 1984
END

SIZE 1200 1200
EXTENT 700000 8225000 730000 8255000
UNITS  meters
SYMBOLSET 'c:/apache2/cat_br/mapa/symbols/symbset.sym'
FONTSET   'c:/apache2/cat_br/mapa/fonts/fonts.fnt'
IMAGECOLOR 255 255 255

#
# Start of web interface definition
#
WEB
 LOG catbr_tematico.log
 TEMPLATE catbr_tematico.html
 IMAGEPATH 'c:/apache2/htdocs/tmp/'
 IMAGEURL 'http://localhost/tmp/'
 EMPTY 'http://localhost/catastro_br/nada.html'
 
 METADATA
  WMS_ONLINERESOURCE 'http://localhost/cgi-bin/mapserv.exe?map=c:/apache2/cat_br/mapa/catbr_tematico.map'
  WMS_SRS 'epsg:32720'
  WMS_ACCESSCONSTRAINTS 'none'
  WMS_TITLE 'CATBR_TEMATICO'
  WMS_FEATURE_INFO_MIME_TYPE 'text/html'
  WMS_ABSTRACT ''
 END  #METADATA

END  #HEADER

OUTPUTFORMAT
    NAME 'AGG'
    DRIVER 'AGG/PNG'
    MIMETYPE 'image/png'
    IMAGEMODE RGB
  	FORMATOPTION 'QUALITY=100'		
END

#OUTPUTFORMAT
#  NAME 'png'
#	DRIVER 'GDAL/PNG'
#	MIMETYPE 'image/png'
#	IMAGEMODE RGB
#	EXTENSION 'png'
#	FORMATOPTION 'QUALITY=100'
#END

SYMBOL
   NAME 'circle'
   TYPE ellipse
   FILLED true
   POINTS
     1 1
   END
END

#
# Start of reference map
#
REFERENCE
  STATUS OFF
  IMAGE 'c:/apache2/htdocs/catastro_br/data/reference.gif'
  SIZE 120 120
  EXTENT -70.254 -23.569 -56.844 -8.994
  COLOR -1 -1 -1
  OUTLINECOLOR 255 0 0
END  #REFERENCE

#
# Start of legend
#
LEGEND
  STATUS OFF
  KEYSIZE 16 8
  TEMPLATE 'legend.html'
  LABEL
    COLOR 120 120 120
  END # ENDE LABEL
END   #LEGEND

#
# Start of scalebar
#
SCALEBAR
 STATUS EMBED
 POSITION lr
 STYLE 0
 INTERVALS 3
 IMAGECOLOR 255 255 255
 LABEL
  COLOR 50 50 50
  SIZE MEDIUM  #SMALL #GIANT
 END  #ENDE LABEL
 #SIZE 150 2
 #SIZE 304 4   #Mapsize 700+700
 Size 400 8    #Mapsize 1400+1400
 TRANSPARENT ON
 COLOR 50 50 50
 BACKGROUNDCOLOR 255 255 255
 OUTLINECOLOR 50 50 50
 UNITS METERS
END   #SCALEBAR

