     EXPRESSION (( '[pos]' == 'CEN' ) AND ('[user_id]' == 'AAA' ))
      LABEL
       TYPE TRUETYPE
       FONT tahoma
       SIZE 10
       ANGLE 0
       COLOR 0 0 255
       BUFFER 3
			 OFFSET 0 0
       POSITION cc
       PARTIALS TRUE
			 FORCE TRUE
			 ANTIALIAS TRUE
      END
     END  # CLASS
				 
